<?php
if (($_GET["key"] ?? "") !== "fsa-hub-deploy-2026") { die("Acesso negado."); }
header("Content-Type: text/plain; charset=utf-8");
echo "=== Instalando script de migracao ===

";
$dir = rtrim(__DIR__, "/");
$files = array(
  "modules/formularios/migrar_dados.php" => "",
);
foreach ($files as $path => $content) {
  $full = $dir . "/" . $path;
  @mkdir(dirname($full), 0755, true);
  file_put_contents($full, base64_decode($content));
  @chmod($full, 0644);
  echo "  OK: $path
";
}
echo "
Agora acesse: /conecta/modules/formularios/migrar_dados.php?key=fsa-hub-deploy-2026
";
